answer.en:
### Custom Hook for Form State with Validation

Controlled inputs give React full ownership of form values, enabling real-time validation. A custom hook encapsulates this logic so it's reusable. The key: track `touched` state separately so validation errors only appear after the user visits a field.

```typescript
import { useState, useCallback } from 'react';

type Validator<T> = (values: T) => Partial<Record<keyof T, string>>;

function useForm<T extends Record<string, string>>(
  initialValues: T,
  validate: Validator<T>
) {
  const [values, setValues] = useState<T>(initialValues);
  const [errors, setErrors] = useState<Partial<Record<keyof T, string>>>({});
  const [touched, setTouched] = useState<Partial<Record<keyof T, boolean>>>({});

  const handleChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    const updated = { ...values, [name]: value } as T;
    setValues(updated);
    // Revalidate the changed field immediately (only if already touched)
    if (touched[name as keyof T]) {
      setErrors(validate(updated));
    }
  }, [values, touched, validate]);

  const handleBlur = useCallback((e: React.FocusEvent<HTMLInputElement>) => {
    const { name } = e.target;
    setTouched(prev => ({ ...prev, [name]: true }));
    setErrors(validate(values));
  }, [values, validate]);

  const isValid = Object.keys(validate(values)).length === 0;
  return { values, errors, touched, handleChange, handleBlur, isValid };
}

// Usage — controlled inputs with inline validation
function RegisterForm() {
  const { values, errors, touched, handleChange, handleBlur, isValid } = useForm(
    { email: '', password: '' },
    ({ email, password }) => {
      const e: Partial<Record<'email' | 'password', string>> = {};
      if (!email.includes('@')) e.email = 'Enter a valid email';
      if (password.length < 8)  e.password = 'Minimum 8 characters';
      return e;
    }
  );

  return (
    <form>
      <div>
        <input name="email" value={values.email} onChange={handleChange} onBlur={handleBlur} />
        {touched.email && errors.email && <span style={{ color: 'red' }}>{errors.email}</span>}
      </div>
      <div>
        <input type="password" name="password" value={values.password} onChange={handleChange} onBlur={handleBlur} />
        {touched.password && errors.password && <span style={{ color: 'red' }}>{errors.password}</span>}
      </div>
      <button type="submit" disabled={!isValid}>Register</button>
    </form>
  );
}
```

**Common interview trap:** Mixing controlled and uncontrolled on the same input — setting `value` without `onChange` makes the field read-only; adding `defaultValue` alongside `value` causes React to warn and behave unpredictably. Choose one model per input and stick with it. For complex real-world forms, libraries like React Hook Form avoid the re-render-per-keystroke overhead of fully controlled inputs.

