    <ErrorBoundary fallbackRender={({ error }) => <div>Ошибка загрузки: {error.message}</div>}>
      <Suspense fallback={<div className="page-loader">Загрузка…</div>}>
        <Outlet />
      </Suspense>
    </ErrorBoundary>
  );
}

const router = createBrowserRouter([
  {
    path: '/',
    element: <PageWrapper />,
    children: [
      { path: 'dashboard', element: <Dashboard /> },
      { path: 'settings', element: <Settings /> },
    ],
  },
]);

export default function App() {
  return <RouterProvider router={router} />;
}

// Prefetch чанка при наведении — убирает задержку восприятия
function NavLink({ to, chunkImport, children }: { to: string; chunkImport: () => Promise<unknown>; children: React.ReactNode }) {
  return (
    <a href={to} onMouseEnter={() => chunkImport()}>
      {children}
    </a>
  );
}
```

**Типичная ошибка на интервью:** Определять `lazy()` внутри тела компонента — `const Comp = lazy(() => import('./X'))` внутри рендера создаёт новый Promise при каждом рендере, обходя кеш React и повторно загружая чанк. Всегда определяйте lazy-компоненты на уровне модуля (вверху файла). Вторая ловушка: забыть `ErrorBoundary` вокруг lazy-компонентов — ошибки загрузки чанка (сетевые ошибки, новый деплой в процессе сессии) без неё крашат весь UI.

